/**
 * Unit tests for version-sync hook
 * Tests version consistency checking across package.json and pyproject.toml
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../../fixtures/mock-common.js';

vi.mock('../../../lib/common.js', () => mockCommonBasic());

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
  readFileSync: vi.fn(() => '{}'),
}));

vi.mock('node:path', () => {
  const named = {
    join: vi.fn((...args: string[]) => args.join('/')),
    basename: vi.fn((p: string) => p.split('/').pop() || ''),
    dirname: vi.fn((p: string) => p.split('/').slice(0, -1).join('/')),
    resolve: vi.fn((...a: string[]) => a.join('/')),
    sep: '/',
  };
  return { ...named, default: named };
});

import { versionSync } from '../../../pretool/bash/version-sync.js';
import type { HookInput } from '../../../types.js';
import { existsSync, readFileSync } from 'node:fs';
import { createTestContext } from '../../fixtures/test-context.js';

function makeInput(command: string): HookInput {
  return {
    tool_name: 'Bash',
    session_id: 'test-session-123',
    project_dir: '/test/project',
    tool_input: { command },
  };
}

let ctx: ReturnType<typeof createTestContext>;

describe('version-sync', () => {
  beforeEach(() => {
    ctx = createTestContext();
    vi.clearAllMocks();
    vi.mocked(existsSync).mockReturnValue(false);
    vi.mocked(readFileSync).mockReturnValue('{}');
  });

  // --- Silent cases ---

  it('returns silent success for non-version commands', () => {
    const result = versionSync(makeInput('npm install'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
    expect(result.hookSpecificOutput).toBeUndefined();
  });

  it('returns silent success for git commit', () => {
    const result = versionSync(makeInput('git commit -m "bump"'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('returns silent success when only package.json exists', () => {
    vi.mocked(existsSync).mockImplementation((p: unknown) => {
      return String(p).includes('package.json');
    });
    vi.mocked(readFileSync).mockReturnValue(JSON.stringify({ version: '1.0.0' }));

    const result = versionSync(makeInput('npm version patch'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
    expect(result.hookSpecificOutput).toBeUndefined();
  });

  it('returns silent success when versions are in sync', () => {
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockImplementation((p: unknown) => {
      const path = String(p);
      if (path.includes('package.json')) return JSON.stringify({ version: '1.0.0' });
      if (path.includes('pyproject.toml')) return 'version = "1.0.0"';
      return '{}';
    });

    const result = versionSync(makeInput('npm version patch'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  // --- Context injection cases ---

  it('returns mismatch context when versions differ', () => {
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockImplementation((p: unknown) => {
      const path = String(p);
      if (path.includes('package.json')) return JSON.stringify({ version: '1.0.0' });
      if (path.includes('pyproject.toml')) return 'version = "1.1.0"';
      return '{}';
    });

    const result = versionSync(makeInput('npm version minor'), ctx);

    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.additionalContext).toContain('Version mismatch');
    expect(result.hookSpecificOutput?.additionalContext).toContain('package.json');
    expect(result.hookSpecificOutput?.additionalContext).toContain('pyproject.toml');
    expect(result.hookSpecificOutput?.additionalContext).toContain('1.0.0');
    expect(result.hookSpecificOutput?.additionalContext).toContain('1.1.0');
  });

  it('triggers on poetry version command', () => {
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockImplementation((p: unknown) => {
      const path = String(p);
      if (path.includes('package.json')) return JSON.stringify({ version: '2.0.0' });
      if (path.includes('pyproject.toml')) return 'version = "2.1.0"';
      return '{}';
    });

    const result = versionSync(makeInput('poetry version patch'), ctx);

    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.additionalContext).toContain('Version mismatch');
  });

  it('logs permission and hook event on mismatch', () => {
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockImplementation((p: unknown) => {
      const path = String(p);
      if (path.includes('package.json')) return JSON.stringify({ version: '1.0.0' });
      if (path.includes('pyproject.toml')) return 'version = "2.0.0"';
      return '{}';
    });

    versionSync(makeInput('npm version major'), ctx);

    expect(ctx.logPermission).toHaveBeenCalledWith('allow', 'Version mismatch detected', expect.any(Object));
    expect(ctx.log).toHaveBeenCalledWith('version-sync', expect.stringContaining('1.0.0'));
  });

  it('logs in-sync permission when versions match', () => {
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockImplementation((p: unknown) => {
      const path = String(p);
      if (path.includes('package.json')) return JSON.stringify({ version: '3.0.0' });
      if (path.includes('pyproject.toml')) return 'version = "3.0.0"';
      return '{}';
    });

    versionSync(makeInput('npm version patch'), ctx);

    expect(ctx.logPermission).toHaveBeenCalledWith('allow', 'Versions in sync: 3.0.0', expect.any(Object));
  });
});
